import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { PiggyBank, Plus, AlertCircle, ArrowUpCircle, ArrowDownCircle, Target, CreditCard } from 'lucide-react';
import '../styles/Orcamento.css';

const Orcamento = () => {
  const [loading, setLoading] = useState(true);
  const [dados, setDados] = useState({
    metaGlobal: 0,
    gastoTotal: 0,
    receitaTotal: 0,
    categorias: []
  });

  useEffect(() => {
    buscarDadosReais();
  }, []);

  async function buscarDadosReais() {
    setLoading(true);
    try {
      // 1. Buscar Proventos (Entradas)
      const { data: proventos } = await supabase.from('proventos').select('valor');
      const totalProventos = proventos?.reduce((acc, cur) => acc + Number(cur.valor), 0) || 0;

      // 2. Buscar Compras (Saídas Variáveis)
      const { data: compras } = await supabase
        .from('compras')
        .select('valor_total, categoria_id')
        .eq('tipo_despesa', 'Gastos Variáveis');

      // 3. Buscar Gastos do Cartão de Crédito
      // Ajuste o nome da tabela 'faturas' ou 'cartao_despesas' se for diferente no seu banco
      const { data: cartao } = await supabase
        .from('cartao_despesas') 
        .select('valor, categoria_id');

      const totalGastosCompras = compras?.reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0;
      const totalGastosCartao = cartao?.reduce((acc, cur) => acc + Number(cur.valor), 0) || 0;
      
      const gastoTotalGeral = totalGastosCompras + totalGastosCartao;

      // 4. Buscar Categorias e cruzar com as DUAS fontes de despesa
      const { data: cats } = await supabase.from('categorias').select('*').order('nome', { ascending: true });

      const categoriasComSoma = cats.map(cat => {
        // Soma compras desta categoria
        const somaCompras = compras
          ?.filter(c => c.categoria_id === cat.id)
          .reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0;
        
        // Soma cartão desta categoria
        const somaCartao = cartao
          ?.filter(c => c.categoria_id === cat.id)
          .reduce((acc, cur) => acc + Number(cur.valor), 0) || 0;
        
        return { 
          ...cat, 
          gastoReal: somaCompras + somaCartao,
          meta: cat.meta_categoria || 0 // Usando o novo nome da coluna que criamos
        };
      });

      // Cálculo da Meta Global baseada na soma das metas das categorias
      const somaMetas = categoriasComSoma.reduce((acc, cur) => acc + (Number(cur.meta) || 0), 0);

      setDados({
        metaGlobal: somaMetas > 0 ? somaMetas : totalProventos,
        gastoTotal: gastoTotalGeral,
        receitaTotal: totalProventos,
        categorias: categoriasComSoma
      });

    } catch (err) {
      console.error("Erro ao carregar dados:", err);
    } finally {
      setLoading(false);
    }
  }

  const formatMoney = (v) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const porcGlobal = (dados.gastoTotal / dados.metaGlobal) * 100;

  if (loading) return <div className="loading-state">Carregando indicadores...</div>;

  return (
    <div className="orcamento-container fade-in">
      <header className="orcamento-header">
        <div>
           <h2>Painel de Orçamento</h2>
           <p>Consolidado: Variáveis + Cartão</p>
        </div>
        <button className="btn-ajuste" onClick={() => window.location.href='/categorias'}>
          <Target size={18} /> Configurar Metas
        </button>
      </header>

      {/* SEÇÃO 1: USO DO LIMITE GLOBAL */}
      <h3 className="section-title">Uso do Limite Global</h3>
      <section className="meta-global-card">
        <div className="meta-info">
          <div className="meta-text">
            <span className="label">Status do Mês</span>
            <h3>{formatMoney(dados.gastoTotal)} <small>/ {formatMoney(dados.metaGlobal)}</small></h3>
          </div>
          <PiggyBank size={40} className="icon-main" />
        </div>
        <div className="progress-bar-container">
          <div 
            className={`progress-bar-fill ${porcGlobal > 100 ? 'over-limit' : ''}`} 
            style={{ width: `${Math.min(porcGlobal, 100)}%` }} 
          />
        </div>
        <div className="meta-footer">
          <span className="progress-label">{porcGlobal.toFixed(1)}% consumido</span>
          <span className="remaining-label">Saldo: {formatMoney(Math.max(0, dados.metaGlobal - dados.gastoTotal))}</span>
        </div>
      </section>

      <div className="two-columns-grid">
        {/* SEÇÃO 2: PROVENTOS */}
        <section className="orc-section">
          <h3 className="section-title"><ArrowUpCircle size={18} color="#10b981" /> Proventos</h3>
          <div className="summary-box proventos-bg">
            <span className="label">Receita Acumulada</span>
            <p className="value">{formatMoney(dados.receitaTotal)}</p>
          </div>
        </section>

        {/* SEÇÃO 3: DESPESAS (VARIÁVEIS + CARTÃO) */}
        <section className="orc-section">
          <h3 className="section-title"><CreditCard size={18} color="#ef4444" /> Total de Despesas</h3>
          <div className="summary-box despesas-bg">
            <span className="label">Variáveis + Cartão</span>
            <p className="value">{formatMoney(dados.gastoTotal)}</p>
          </div>
        </section>
      </div>

      <h3 className="section-title" style={{marginTop: '30px'}}>Detalhamento por Categoria</h3>
      <div className="orcamento-grid">
        {dados.categorias.filter(c => c.tipo === 'despesa').map((cat) => {
          const porc = cat.meta > 0 ? (cat.gastoReal / cat.meta) * 100 : 0;
          const excedeu = cat.gastoReal > cat.meta && cat.meta > 0;

          return (
            <div key={cat.id} className={`categoria-card ${excedeu ? 'card-excedido' : ''}`}>
              <div className="categoria-header">
                <div className="cat-info-main">
                  <div className="dot" style={{backgroundColor: cat.cor}}></div>
                  <span className="cat-nome">{cat.nome}</span>
                </div>
                {excedeu && <AlertCircle size={16} color="#ef4444" />}
              </div>
              <div className="cat-body">
                <div className="categoria-valores">
                  <div className="v-group">
                    <label>Gasto</label>
                    <span className="valor-gasto">{formatMoney(cat.gastoReal)}</span>
                  </div>
                  <div className="v-group align-right">
                    <label>Meta</label>
                    <span className="valor-meta">{formatMoney(cat.meta)}</span>
                  </div>
                </div>
                <div className="mini-progress-bg">
                  <div 
                    className="mini-progress-fill" 
                    style={{ 
                      width: `${Math.min(porc, 100)}%`, 
                      backgroundColor: excedeu ? '#ef4444' : cat.cor 
                    }} 
                  />
                </div>
                <span className="porc-individual">{porc.toFixed(0)}%</span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Orcamento;
